const fs = require('fs');
const path = require('path');

// Function to generate a package-lock.json file
function generatePackageLockJson(packageName, version) {
  const lockFilePath = path.join(__dirname, 'package-lock.json');
  const lockFileContent = JSON.stringify({
    name: packageName,
    version: version,
    dependencies: {},
  }, null, 2);
  fs.writeFileSync(lockFilePath, lockFileContent);
}

// Function to update the package-lock.json file with new dependency versions
function updatePackageLockJson(packageName, version) {
  const lockFilePath = path.join(__dirname, 'package-lock.json');
  const lockFileContent = JSON.parse(fs.readFileSync(lockFilePath));
  if (!lockFileContent.dependencies[packageName]) {
    lockFileContent.dependencies[packageName] = {};
  }
  lockFileContent.dependencies[packageName].version = version;
  fs.writeFileSync(lockFilePath, JSON.stringify(lockFileContent, null, 2));
}

// Function to maintain the package-lock.json file for consistent dependency versions across environments
function maintainPackageLockJson() {
  const lockFilePath = path.join(__dirname, 'package-lock.json');
  const lockFileContent = JSON.parse(fs.readFileSync(lockFilePath));
  const dependencies = Object.keys(lockFileContent.dependencies);
  for (const dependency of dependencies) {
    const version = lockFileContent.dependencies[dependency].version;
    updatePackageLockJson(dependency, version);
  }
}

// Function to update the package-lock.json file with new dependency versions and maintain consistency across environments
function updateAndMaintainPackageLockJson(packageName, version) {
  updatePackageLockJson(packageName, version);
  maintainPackageLockJson();
}